#include<stdio.h>
int main()
{
    int n;
    char s[10];
    scanf("%d",&n);
    scanf("%s",s);
    if(n==6)
        printf("espeon");
    else if(n==8)
    {
        printf("vaporeon");
    }
    else
    {
        if(s[0]=='j' || s[1]=='o' || s[3]=='t')
            printf("jolteon");
        else if(s[0]=='f' || (s[1]=='l' && s[2]=='a' && s[3]=='r') || (s[3]=='r' && (s[2]=='a' || s[1]=='l')))
            printf("flareon");
        else if(s[0]=='u' || s[1]=='m' || s[2]=='b')
            printf("umbreon");
        else if(s[0]=='l' || s[1]=='e' || s[3]=='f')
            printf("leafeon");
        else if(s[0]=='g' || s[3]=='c')
            printf("glaceon");
        else if(s[0]=='s' || s[1]=='y' || s[3]=='v')
            printf("sylveon");
    }
    return 0;
}

