use std::io::stdin;
fn main() {
    let evolutions = ["vaporeon", "jolteon", "flareon", "espeon", "umbreon", "leafeon", "glaceon", "sylveon"];

    let mut entry = String::new();
    stdin().read_line(&mut entry).unwrap();
    let len:usize = entry.trim().parse().unwrap();
    entry.clear();
    stdin().read_line(&mut entry).unwrap();
    let name = entry.trim();
    let mut coord:Vec<(char, usize)> = vec!();
    for (i, c) in name.chars().enumerate(){
        if c != '.' {
            coord.push((c, i));
        }
    }
    for ev in evolutions.iter() {
        if len == ev.len(){
            let mut is_it = true;
            let chars :Vec<char> = ev.chars().collect();
            for i in &coord{
                if i.0 != chars[i.1] {
                    is_it = false;
                    break;
                }
            }
            if is_it {
                println!("{}", ev);
                break;
            }
        }
    }
}
